#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int sum = 0, x;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &x);
            sum += x;
        }
        if (sum % 2 != 0) {
            printf("-1\n");
        } else {
            if (sum < 0) sum = -sum;
            printf("%d\n", sum / 2);
        }
    }
    return 0;
}

